# Metadata Sanitizer - Prevents gRPC Metadata Injection
# ============================================================

class MetadataSanitizer:
    """
    Sanitizes and validates metadata keys and values to prevent
    gRPC metadata injection attacks.
    
    gRPC metadata keys must be:
    - ASCII lowercase letters, digits, hyphens, underscores, dots
    - Must not start with 'grpc-' (reserved prefix)
    
    gRPC metadata values must be:
    - Valid ASCII printable strings (for non-binary headers)
    - Binary headers (keys ending in '-bin') must be bytes
    """

    # Allowed characters in metadata keys: lowercase alphanumeric, hyphen, underscore, dot
    _VALID_KEY_PATTERN = re.compile(r'^[a-z0-9][a-z0-9._-]*$')

    # Reserved gRPC internal prefixes that must not be set by users
    _RESERVED_PREFIXES = ('grpc-',)

    # Headers that should never be forwarded from external requests
    _BLOCKED_HEADERS = frozenset({
        'grpc-timeout',
        'grpc-encoding',
        'grpc-accept-encoding',
        'grpc-status',
        'grpc-message',
        'grpc-status-details-bin',
        'te',
        'host',
        'content-type',
        'content-length',
        'connection',
        'transfer-encoding',
        'upgrade',
        'keep-alive',
        'proxy-authorization',
        'proxy-authenticate',
        'proxy-connection',
        'authorization',  # Handle auth separately through dedicated mechanism
    })

    # Allowlist of header prefixes that are safe to forward
    _ALLOWED_PREFIXES = (
        'x-',
        'x-custom-',
        'x-request-',
        'x-correlation-',
        'x-trace-',
        'x-b3-',       # Zipkin tracing
        'x-datadog-',  # Datadog tracing
        'traceparent',
        'tracestate',
    )

    # Maximum limits to prevent resource exhaustion
    _MAX_KEY_LENGTH = 128
    _MAX_VALUE_LENGTH = 8192
    _MAX_METADATA_PAIRS = 64

    @classmethod
    def sanitize_key(cls, key: str) -> str:
        """
        Sanitize a metadata key.
        
        - Converts to lowercase
        - Validates against allowed pattern
        - Checks against reserved prefixes
        - Enforces length limits
        
        Returns sanitized key or raises ValueError.
        """
        if not isinstance(key, str):
            raise ValueError(f"Metadata key must be a string, got {type(key).__name__}")

        # Normalize to lowercase
        key = key.lower().strip()

        if not key:
            raise ValueError("Metadata key must not be empty")

        if len(key) > cls._MAX_KEY_LENGTH:
            raise ValueError(
                f"Metadata key exceeds maximum length of {cls._MAX_KEY_LENGTH}: "
                f"got {len(key)} characters"
            )

        # Check for null bytes or control characters
        if any(ord(c) < 0x20 or ord(c) == 0x7f for c in key):
            raise ValueError(
                f"Metadata key contains control characters: {key!r}"
            )

        # Validate key format
        if not cls._VALID_KEY_PATTERN.match(key):
            raise ValueError(
                f"Invalid metadata key format: {key!r}. "
                "Keys must contain only lowercase letters, digits, hyphens, "
                "underscores, and dots, and must start with a letter or digit."
            )

        # Check reserved prefixes
        for prefix in cls._RESERVED_PREFIXES:
            if key.startswith(prefix):
                raise ValueError(
                    f"Metadata key uses reserved prefix '{prefix}': {key!r}"
                )

        # Check blocked headers
        if key in cls._BLOCKED_HEADERS:
            raise ValueError(
                f"Metadata key is blocked and cannot be forwarded: {key!r}"
            )

        return key

    @classmethod
    def sanitize_value(cls, value, key: str = "") -> str:
        """
        Sanitize a metadata value.
        
        - For binary headers (key ending in '-bin'), value must be bytes
        - For regular headers, value must be valid ASCII printable string
        - Enforces length limits
        - Strips leading/trailing whitespace
        - Rejects control characters, newlines (CRLF injection prevention)
        
        Returns sanitized value or raises ValueError.
        """
        is_binary = key.endswith('-bin')

        if is_binary:
            if isinstance(value, str):
                value = value.encode('utf-8')
            if not isinstance(value, bytes):
                raise ValueError(
                    f"Binary metadata value (key ending in '-bin') must be bytes, "
                    f"got {type(value).__name__}"
                )
            if len(value) > cls._MAX_VALUE_LENGTH:
                raise ValueError(
                    f"Binary metadata value exceeds maximum length of "
                    f"{cls._MAX_VALUE_LENGTH}: got {len(value)} bytes"
                )
            return value

        # Non-binary value handling
        if isinstance(value, bytes):
            try:
                value = value.decode('ascii')
            except UnicodeDecodeError:
                raise ValueError(
                    "Non-binary metadata value contains non-ASCII characters. "
                    "Use a '-bin' suffixed key for binary data."
                )

        if not isinstance(value, str):
            raise ValueError(
                f"Metadata value must be a string, got {type(value).__name__}"
            )

        # Strip whitespace
        value = value.strip()

        if len(value) > cls._MAX_VALUE_LENGTH:
            raise ValueError(
                f"Metadata value exceeds maximum length of "
                f"{cls._MAX_VALUE_LENGTH}: got {len(value)} characters"
            )

        # CRITICAL: Reject control characters including \r, \n, \0
        # This prevents CRLF injection and header injection attacks
        for i, c in enumerate(value):
            code = ord(c)
            # Allow horizontal tab (0x09) and printable ASCII (0x20-0x7E)
            if code == 0x09:
                continue
            if code < 0x20 or code == 0x7f:
                raise ValueError(
                    f"Metadata value contains illegal control character "
                    f"at position {i}: 0x{code:02x}. "
                    "This may indicate a header injection attempt."
                )

        # Additional check: reject values that look like they're trying to
        # inject additional headers (contains literal \r\n patterns)
        if '\r' in value or '\n' in value:
            raise ValueError(
                "Metadata value contains newline characters. "
                "This may indicate a CRLF injection attempt."
            )

        return value

    @classmethod
    def is_allowed_header(cls, key: str) -> bool:
        """
        Check if a header key is in the allowlist of forwardable headers.
        Uses an allowlist approach rather than blocklist for security.
        """
        key_lower = key.lower()

        # Check against allowlist prefixes
        for prefix in cls._ALLOWED_PREFIXES:
            if key_lower.startswith(prefix):
                return True

        return False

    @classmethod
    def sanitize_metadata(cls, raw_metadata: dict, use_allowlist: bool = True) -> list:
        """
        Sanitize a complete metadata dictionary.
        
        Args:
            raw_metadata: Dictionary of header key-value pairs from HTTP request
            use_allowlist: If True, only forward headers matching the allowlist
            
        Returns:
            List of (key, value) tuples safe for use as gRPC metadata
            
        Raises:
            ValueError: If metadata exceeds maximum pair count
        """
        if not isinstance(raw_metadata, dict):
            raise ValueError(
                f"Metadata must be a dictionary, got {type(raw_metadata).__name__}"
            )

        sanitized = []
        skipped = []

        if len(raw_metadata) > cls._MAX_METADATA_PAIRS:
            raise ValueError(
                f"Too many metadata pairs: {len(raw_metadata)} exceeds "
                f"maximum of {cls._MAX_METADATA_PAIRS}"
            )

        for raw_key, raw_value in raw_metadata.items():
            try:
                # Sanitize the key
                clean_key = cls.sanitize_key(raw_key)

                # Apply allowlist filtering
                if use_allowlist and not cls.is_allowed_header(clean_key):
                    skipped.append((raw_key, "not in allowlist"))
                    continue

                # Sanitize the value
                clean_value = cls.sanitize_value(raw_value, key=clean_key)

                sanitized.append((clean_key, clean_value))

            except ValueError as e:
                # Log the rejection but don't fail the entire request
                skipped.append((raw_key, str(e)))
                continue

        if skipped:
            # In production, use proper logging
            import logging
            logger = logging.getLogger(__name__)
            for key, reason in skipped:
                logger.warning(
                    "Skipped metadata key %r: %s", key, reason
                )

        return sanitized


